package ir.tahamohamadi.resume; import ir.tahamohamadi.common.domain.ContentStatus; import ir.tahamohamadi.common.persistence.AuditedSoftDeletableEntity; import jakarta.persistence.*; import lombok.*; import java.time.LocalDate;
@Entity @Table(name="resume_entry") @Getter @NoArgsConstructor(access=AccessLevel.PROTECTED) public class ResumeEntry extends AuditedSoftDeletableEntity { @Enumerated(EnumType.STRING) @Column(name="entry_type",nullable=false) private ResumeEntryType entryType; @Enumerated(EnumType.STRING) @Column(nullable=false) private ContentStatus status; @Column(name="started_on",nullable=false) private LocalDate startedOn; @Column(name="ended_on") private LocalDate endedOn; @Column(name="is_current",nullable=false) private boolean current; @Column(name="sort_order",nullable=false) private int sortOrder; }
